const all = $input.all();
const results = [];

for (const item of all) {
  // handle both {results: [...]} and flat array
  const raw = item.json.results || [item.json];

  for (const x of raw) {
    if (!x.ticker || x.error) continue;

    let score = 0;

    // ── 1. IV RANK (0-30 points) ──────────────────────────────────
    // Higher IV rank = options more expensive = better premium to sell
    // Sweet spot: 30-80 (not too low, not at extreme peak)
    const ivRank = x.ivRank ?? 0;
    if (ivRank >= 50) score += 30;
    else if (ivRank >= 30) score += 22;
    else if (ivRank >= 15) score += 12;
    else score += 0;

    // ── 2. VRP — IV vs RV (0-25 points) ──────────────────────────
    // Positive VRP = IV overpriced vs realized moves = sell premium
    const vrp = x.vrp ?? 0;
    if (vrp >= 0.15) score += 25;
    else if (vrp >= 0.08) score += 18;
    else if (vrp >= 0.03) score += 10;
    else if (vrp > 0) score += 4;
    else score += 0; // negative VRP = IV cheap = not ideal for selling

    // ── 3. IV DIRECTION (0-15 points) ────────────────────────────
    // Rising IV = options getting more expensive = better time to sell
    if (x.ivDirection === "rising") score += 15;
    else if (x.ivDirection === "falling") score += 0;

    // ── 4. PUT/CALL SIGNAL (0-15 points) ─────────────────────────
    // Bullish put/call = more call activity = stock sentiment positive
    if (x.putCallSignal === "bullish") score += 15;
    else if (x.putCallSignal === "neutral") score += 7;
    else score += 0; // bearish

    // ── 5. CURRENT IV LEVEL (0-10 points) ────────────────────────
    // Higher absolute IV = fatter premiums on covered calls
    const iv = x.ivCurrent ?? 0;
    if (iv >= 0.60) score += 10;
    else if (iv >= 0.40) score += 8;
    else if (iv >= 0.25) score += 5;
    else if (iv >= 0.15) score += 2;
    else score += 0;

    // ── 6. LIQUIDITY (0-5 points) ─────────────────────────────────
    // High call OI = liquid options = tighter spreads = easier to trade
    const callOI = x.callOI ?? 0;
    if (callOI >= 100000) score += 5;
    else if (callOI >= 50000) score += 4;
    else if (callOI >= 10000) score += 2;
    else score += 0;

    // clamp 0-100
    score = Math.max(0, Math.min(100, score));

    results.push({
      json: {
        ticker:              x.ticker,
        price:               x.price,
        score:               score,
        ivRank:              x.ivRank,
        ivCurrent:           x.ivCurrent,
        ivDirection:         x.ivDirection,
        ivChange:            x.ivChange,
        rv30d:               x.rv30d,
        vrp:                 x.vrp,
        vrpSignal:           x.vrpSignal,
        putCallRatioOI:      x.putCallRatioOI,
        putCallRatioVolume:  x.putCallRatioVolume,
        putCallSignal:       x.putCallSignal,
        callOI:              x.callOI,
        putOI:               x.putOI,
        callVolume:          x.callVolume,
        putVolume:           x.putVolume,
        // human-readable signals
        signal: (
          x.vrpSignal === "sell_premium" && x.ivDirection === "rising"
            ? "STRONG_SELL_PREMIUM"
            : x.vrpSignal === "sell_premium"
            ? "SELL_PREMIUM"
            : x.ivDirection === "rising"
            ? "WATCH"
            : "SKIP"
        )
      }
    });
  }
}

// sort highest score first
results.sort((a, b) => b.json.score - a.json.score);

// return top 20
return results.slice(0, 10);

