const results = [];

for (const item of items) {
  const data = item.json;
  const ticker = data.ticker;
  const spot = Number(data.spotPrice);
  const calls = data.calls || [];


  if (!spot || !calls.length) {
    results.push({
      json: {
        ticker,
        reason: "Missing spot price or no calls returned",
        spotPrice: spot,
        callCount: calls.length
      }
    });
    continue;
  }

  for (const call of calls) {
    const strike = Number(call.strike);
    const bid = Number(call.bid ?? 0);
    const ask = Number(call.ask ?? 0);
    const oi = Number(call.openInterest ?? 0);
    const volume = Number(call.volume ?? 0);
    const iv = Number(call.impliedVolatility ?? 0);

    if (!strike) continue;
    if (strike < spot) continue;

    const premium = ask || bid || 0;
    if (premium <= 0) continue;

    const premiumYield = premium / spot;
    const upsidePct = (strike - spot) / spot;
    const totalIfCalled = premiumYield + upsidePct;
    const spreadPct = (ask > 0 && bid > 0) ? ((ask - bid) / ask) : null;

    results.push({
      json: {
        ticker,
        expir: call.expiration || null,
        spotPrice: spot,
        strike,
        bid,
        ask,
        premium,
        premiumYield,
        upsidePct,
        totalIfCalled,
        openInterest: oi,
        volume,
        impliedVolatility: iv,
        spreadPct
      }
    });
  }
}

return results;

const now = new Date();

return $input.all().map(item => {
  const x = item.json;

  const spot    = Number(x.spotPrice || 0);
  const strike  = Number(x.strike    || 0);
  const bid     = Number(x.bid       || 0);
  const ask     = Number(x.ask       || 0);
  const oi      = Number(x.openInterest || 0);
  const volume  = Number(x.volume    || 0);
  const iv      = Number(x.impliedVolatility || 0);
  const premium = bid > 0 ? bid : ask;

  const dte = x.expir
    ? Math.ceil((new Date(x.expir) - now) / (1000 * 60 * 60 * 24))
    : null;

  const breakeven        = Number((spot - premium).toFixed(2));
  const breakevenDropPct = Number((premium / spot * 100).toFixed(2));
  const profitIfOTM_usd  = Number((premium * 100).toFixed(2));
  const profitIfITM_usd  = Number(((strike - spot + premium) * 100).toFixed(2));
  const maxLoss_usd      = Number(((spot - premium) * 100).toFixed(2));
  const riskReward       = maxLoss_usd > 0 ? Number((profitIfITM_usd / maxLoss_usd).toFixed(4)) : null;
  const liquidityScore   = Number((Math.min(oi / 500, 5) + Math.min(volume / 100, 5)).toFixed(2));
  const spreadPct        = ask > 0 ? Number(((ask - bid) / ask * 100).toFixed(2)) : null;
  const premiumYieldPct  = Number((premium / spot * 100).toFixed(4));

  let qualityTag = "SKIP";
  if (breakevenDropPct >= 2 && spreadPct !== null && spreadPct <= 30 && oi >= 50 && premiumYieldPct >= 0.5) qualityTag = "GOOD";
  if (breakevenDropPct >= 3 && spreadPct !== null && spreadPct <= 20 && oi >= 100 && premiumYieldPct >= 1) qualityTag = "STRONG";

  return {
    json: {
      // ── Identity ──────────────────────────────────
      ticker:               x.ticker,
      expiry:               x.expir,
      daysToExpiry:         dte,
      currentStockPrice:    spot,
      strikePrice:          strike,

      // ── Core metrics ──────────────────────────────
      premiumReceived:      premium,
      breakevenPrice:       breakeven,
      stockCanDropBy:       `${breakevenDropPct}%`,

      // ── Profit scenarios ──────────────────────────
      profitIfStockStaysFlat:    `$${profitIfOTM_usd}`,
      profitIfStockAboveStrike:   `$${profitIfITM_usd}`,
      worstCaseLoss:             `$${maxLoss_usd}`,

      // ── Risk ──────────────────────────────────────
      rewardVsRisk:         riskReward,

      // ── Liquidity ─────────────────────────────────
      liquidityScore:       liquidityScore,
      openInterest:         oi,
      volume,

      // ── Verdict ───────────────────────────────────
      rating:               qualityTag,
    }
  };
});

